sql:
SELECT ref_name
FROM refs
WHERE rating = (
  SELECT MAX(rating)
  FROM refs
);

SELECT referee_id, COUNT(*) AS num_reviews
FROM game_reviews
GROUP BY referee_id;

SELECT LOG(AVG(seconds_left))
FROM game_reviews
WHERE call_type = 'foul';

SELECT game_reviews.game_id, players.player_name
FROM game_reviews
INNER JOIN players ON game_reviews.committing_player = players.player_name;

SELECT decision_maker_id, COUNT(decision_id) as num_decisions
FROM review_decisions
GROUP BY decision_maker_id;

SELECT ref_name, rating
FROM refs
WHERE rating = (SELECT MAX(rating) FROM refs);

SELECT gr.game_id, gr.period 
FROM game_reviews gr
WHERE gr.committing_player IN (
    SELECT player_name FROM players
)
OR gr.disadvantaged_player IN (
    SELECT player_name FROM players
);
